      buffer[j + y * Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float) * Lx * Ly);

  for (i = 0; i < niter; i++) {
    reference(h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }

  const size_t bytes = sizeof(float) * (size_t)Lx * (size_t)Ly;
  const int N = Lx * Ly;
  int host_dev = omp_get_initial_device();
  int target_dev = omp_get_default_device();

  float *d_in = (float*) omp_target_alloc(bytes, target_dev);
  float *d_out = (float*) omp_target_alloc(bytes, target_dev);
  if (d_in == NULL || d_out == NULL) {
    fprintf(stderr, "Device allocation failed\n");
    exit(1);
  }

  omp_target_memcpy(d_in, buffer, bytes, 0, 0, target_dev, host_dev);

  double t0 = stop_watch(0);

  for (i = 0; i < niter; i++) {
    #pragma omp target teams distribute parallel for is_device_ptr(d_out, d_in)
    for (int idx = 0; idx < N; idx++) {
      int x0 = idx % Lx;
      int y0 = idx / Lx;
      int v00 = y0 * Lx + x0;
      int v0p = y0 * Lx + (x0 + 1) % Lx;
      int v0m = y0 * Lx + (Lx + x0 - 1) % Lx;
      int vp0 = ((y0 + 1) % Ly) * Lx + x0;
      int vm0 = ((Ly + y0 - 1) % Ly) * Lx + x0;
      d_out[v00] = xnorm * d_in[v00] + xdelta * (d_in[v0p] + d_in[v0m] + d_in[vp0] + d_in[vm0]);
    }
    std::swap(d_out, d_in);
  }

  t0 = stop_watch(t0) / (double) niter;

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
         niter, Lx, Ly, t0,
         Lx * Ly * sizeof(float) * 2.0 / (t0 * 1.0e3),
         (Lx * Ly * 6.0) / (t0 * 1.0e3));

  omp_target_memcpy(d_res, d_in, bytes, 0, 0, host_dev, target_dev);

  bool ok = true;
  for (i = 0; i < Lx * Ly; i++) {
    if (fabs(h_in[i] - d_res[i]) > 1e-2) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], d_res[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  omp_target_free(d_in, target_dev);
  omp_target_free(d_out, target_dev);
  free(buffer);
  free(h_out);
  free(h_in);
  free(d_res);
  return 0;
}

