        vertice[i] = (char)root_prefixes_d[idx].board[i];

      depth = depthGlobal;

      do {
        vertice[depth]++;
        bit_test = 0;
        bit_test |= (1 << vertice[depth]);
        if (vertice[depth] == N_l) {
          vertice[depth] = _EMPTY_;
