                    (size_t)n_explorers * sizeof(unsigned long long),
                    0, 0, host, dev);
  omp_target_memcpy(sols_h, sols_d,
                    (size_t)n_explorers * sizeof(unsigned long long),
                    0, 0, host, dev);

