            << 100.0 * ((double)totalPairs / (nAtom*maxNeighbors)) << " %\n";

#pragma omp target data map(to: position[0:nAtom], neighborList[0:nAtom*maxNeighbors]) map(from: h_force[0:nAtom])
  {
    md(position, h_force, neighborList, nAtom, maxNeighbors, lj1, lj2, cutsq);

#pragma omp target update from(h_force[0:nAtom])

    std::cout << "Performing Correctness Check (may take several minutes)\n";
    checkResults<FPTYPE, FORCEVECTYPE, POSVECTYPE>(h_force, position, neighborList, nAtom);

