  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs((double)s - (double)d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = (size_t)input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes);
  b = (T *)malloc(size_bytes);

  T h_mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1;

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = (T)(rand() % 256);
  }

  int host_dev = omp_get_initial_device();
  int dev = omp_get_default_device();

  T *d_a = (T *)omp_target_alloc(size_bytes, dev);
  T *d_b = (T *)omp_target_alloc(size_bytes, dev);
  T *d_mask = (T *)omp_target_alloc(mask_width * sizeof(T), dev);

  omp_target_memcpy(d_a, a, size_bytes, 0, 0, dev, host_dev);
  omp_target_memcpy(d_mask, h_mask, mask_width * sizeof(T), 0, 0, dev, host_dev);

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    int grids = input_width / bs;
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_kernel<T>(d_a, d_b, input_width, mask_width, d_mask, grids, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    omp_target_memcpy(b, d_b, size_bytes, 0, 0, host_dev, dev);
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    int grids = input_width / bs;
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_kernel<T>(d_a, d_b, input_width, mask_width, d_mask, grids, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    omp_target_memcpy(b, d_b, size_bytes, 0, 0, host_dev, dev);
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    int grids = input_width / bs;
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_caching_kernel<T>(d_a, d_b, input_width, mask_width, d_mask, grids, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    omp_target_memcpy(b, d_b, size_bytes, 0, 0, host_dev, dev);
    reference(a, b, h_mask, input_width, mask_width);
  }

  free(a);
  free(b);
  omp_target_free(d_a, dev);
  omp_target_free(d_b, dev);
  omp_target_free(d_mask, dev);
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);

  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width);

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <math.h>
#include <getopt.h>
#include <chrono>
#include <omp.h>

#define D_FACTOR (0.85f)
#ifndef BLOCK_SIZE
#define BLOCK_SIZE 256
#endif

const int max_iter = 1000;
const float threshold = 1e-16f;

void map(const int *__restrict__ pages,
         const float *__restrict__ page_ranks,
         float *__restrict__ maps,
         const unsigned int *__restrict__ noutlinks,
         const int n)
{
#pragma omp target teams distribute parallel for is_device_ptr(pages, page_ranks, maps, noutlinks)
  for (int i = 0; i < n; ++i) {
    float outbound_rank = page_ranks[i] / (float)noutlinks[i];
    for (int j = 0; j < n; ++j) {
      maps[(size_t)i * n + j] = pages[(size_t)i * n + j] * outbound_rank;
    }
  }
}

void reduce(float *__restrict__ page_ranks,
            const float *__restrict__ maps,
            const int n,
            float *__restrict__ dif)
{
#pragma omp target teams distribute parallel for is_device_ptr(page_ranks, maps, dif)
  for (int j = 0; j < n; ++j) {
    float old_rank = page_ranks[j];
    float new_rank = 0.0f;
    for (int i = 0; i < n; ++i) {
      new_rank += maps[(size_t)i * n + j];
    }

    new_rank = ((1.f - D_FACTOR) / n) + (D_FACTOR * new_rank);
    dif[j] = fmaxf(fabsf(new_rank - old_rank), dif[j]);
    page_ranks[j] = new_rank;
  }
}

void map_ref(const int *__restrict__ pages,
             const float *__restrict__ page_ranks,
             float *__restrict__ maps,
             const unsigned int *__restrict__ noutlinks,
             const int n)
{
#pragma omp parallel for
  for (int i = 0; i < n; i++) {
    float outbound_rank = page_ranks[i] / (float)noutlinks[i];
    for (int j = 0; j < n; ++j) {
      maps[(size_t)i * n + j] = pages[(size_t)i * n + j] * outbound_rank;
    }
  }
}

void reduce_ref(float *__restrict__ page_ranks,
                const float *__restrict__ maps,
                const int n,
                float *__restrict__ dif)
{
  const float D_FACTOR_REF = 0.85f;
#pragma omp parallel for
  for (int j = 0; j < n; j++) {
    float old_rank = page_ranks[j];
    float new_rank = 0.0f;
    for (int i = 0; i < n; ++i) {
      new_rank += maps[(size_t)i * n + j];
    }

    new_rank = ((1.f - D_FACTOR_REF) / n) + (D_FACTOR_REF * new_rank);
    dif[j] = fmaxf(fabsf(new_rank - old_rank), dif[j]);
    page_ranks[j] = new_rank;
  }
}

int *random_pages(int n, unsigned int *noutlinks, int divisor)
{
  int i, j, k;
  int *pages = (int *)malloc((size_t)n * n * sizeof(int));

  if (divisor <= 0) {
    fprintf(stderr, "ERROR: Invalid divisor '%d' for random initialization, divisor should be greater or equal to 1\n", divisor);
    exit(1);
  }

  for (i = 0; i < n; ++i) {
    noutlinks[i] = 0;
    for (j = 0; j < n; ++j) {
      if (i != j && (abs(rand()) % divisor == 0)) {
        pages[(size_t)i * n + j] = 1;
        noutlinks[i] += 1;
      }
    }

    if (noutlinks[i] == 0) {
      do {
        k = abs(rand()) % n;
      } while (k == i);
      pages[(size_t)i * n + k] = 1;
      noutlinks[i] = 1;
    }
  }
  return pages;
}

void init_array(float *a, int n, float val)
{
  int i;
  for (i = 0; i < n; ++i) {
    a[i] = val;
  }
}

void usage(char *argv[])
{
  fprintf(stderr, "Usage: %s [-n number of pages] [-i max iterations]"
                  " [-t threshold] [-q divisor for zero density]\n",
          argv[0]);
}

static struct option size_opts[] = {
    {"number of pages", 1, NULL, 'n'},
    {"max number of iterations", 1, NULL, 'i'},
    {"minimum threshold", 1, NULL, 't'},
    {"divisor for zero density", 1, NULL, 'q'},
    {0, 0, 0}};

float maximum_dif(float *difs, int n)
{
  int i;
  float max = 0.0f;
  for (i = 0; i < n; ++i) {
    max = difs[i] > max ? difs[i] : max;
  }
  return max;
}

int main(int argc, char *argv[])
{
  int *pages;
  float *maps;
  float *page_ranks;
  unsigned int *noutlinks;
  int t;
  float max_diff, max_diff_ref;

  int i = 0;
  int n = 1000;
  int iter = max_iter;
  float thresh = threshold;
  int divisor = 2;

  int opt, opt_index = 0;
  while ((opt = getopt_long(argc, argv, "::n:i:t:q:", size_opts, &opt_index)) != -1) {
    switch (opt) {
    case 'n':
      n = atoi(optarg);
      break;
    case 'i':
      iter = atoi(optarg);
      break;
    case 't':
      thresh = atof(optarg);
      break;
    case 'q':
      divisor = atoi(optarg);
      break;
    default:
      usage(argv);
      exit(EXIT_FAILURE);
    }
  }

  size_t rank_size = (size_t)n * sizeof(float);
  size_t map_size = (size_t)n * n * sizeof(float);
  size_t page_size = (size_t)n * n * sizeof(int);
  size_t link_size = (size_t)n * sizeof(unsigned int);

  page_ranks = (float *)malloc(rank_size);
  maps = (float *)malloc(map_size);
  noutlinks = (unsigned int *)malloc(link_size);

  max_diff = max_diff_ref = 99.0f;

  for (i = 0; i < n; ++i) {
    noutlinks[i] = 0;
  }
  pages = random_pages(n, noutlinks, divisor);
  init_array(page_ranks, n, 1.0f / (float)n);

  float *diffs;
  diffs = (float *)malloc(rank_size);

  int device = omp_get_default_device();
  int host = omp_get_initial_device();

  int *d_pages = (int *)omp_target_alloc(page_size, device);
  float *d_maps = (float *)omp_target_alloc(map_size, device);
  float *d_page_ranks = (float *)omp_target_alloc(rank_size, device);
  float *d_diffs = (float *)omp_target_alloc(rank_size, device);
  unsigned int *d_noutlinks = (unsigned int *)omp_target_alloc(link_size, device);

  memset(diffs, 0, rank_size);
  omp_target_memcpy(d_pages, pages, page_size, 0, 0, device, host);
  omp_target_memcpy(d_page_ranks, page_ranks, rank_size, 0, 0, device, host);
  omp_target_memcpy(d_noutlinks, noutlinks, link_size, 0, 0, device, host);
  omp_target_memcpy(d_diffs, diffs, rank_size, 0, 0, device, host);

  size_t block_size = n < BLOCK_SIZE ? n : BLOCK_SIZE;
  size_t num_blocks = (n + block_size - 1) / block_size;
  (void)block_size;
  (void)num_blocks;

  double ktime = 0.0;
  printf("Threshold: %f\n", thresh);

  for (t = 1; t <= iter && max_diff >= thresh; ++t) {
    auto start = std::chrono::high_resolution_clock::now();

    map(d_pages, d_page_ranks, d_maps, d_noutlinks, n);
    reduce(d_page_ranks, d_maps, n, d_diffs);

    auto end = std::chrono::high_resolution_clock::now();
    ktime += std::chrono::duration_cast<std::chrono::duration<double>>(end - start).count();

    omp_target_memcpy(diffs, d_diffs, rank_size, 0, 0, host, device);
    max_diff = maximum_dif(diffs, n);
  }

  omp_target_free(d_pages, device);
  omp_target_free(d_maps, device);
  omp_target_free(d_page_ranks, device);
  omp_target_free(d_noutlinks, device);
  omp_target_free(d_diffs, device);

  fprintf(stderr, "Max difference %f is reached at iteration %d\n", max_diff, t);
  printf("\"Options\": \"-n %d -i %d -t %f\". Total kernel execution time: %lf (s)\n",
         n, iter, thresh, ktime);

  memset(diffs, 0, rank_size);
  for (t = 1; t <= iter && max_diff_ref >= thresh; ++t) {
    map_ref(pages, page_ranks, maps, noutlinks, n);
    reduce_ref(page_ranks, maps, n, diffs);
    max_diff_ref = maximum_dif(diffs, n);
  }
  bool ok = fabsf(max_diff - max_diff_ref) < 1e-3f;
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(pages);
  free(maps);
  free(page_ranks);
  free(noutlinks);
  free(diffs);

  return 0;
}

